import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int maxLength = 10; // Maximum length of buffer
        char[] buffer = new char[maxLength];

        // Copy user input into buffer with proper length checking
        for (int i = 0; i < maxLength && i < input.length(); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));

        // Ensure any remaining characters in user input are not processed to prevent Buffer Overflow

        if (input.length() > maxLength) {
            System.out.println("Input exceeds buffer size. Only first " + maxLength + " characters are processed.");
            // Additional handling or logging can be added here based on requirements
        }
    }
}

